define(["jquery","core/ajax","mod_gestionprojet/cdcf","mod_gestionprojet/autosave"],function($,Ajax,Cdcf,Autosave){"use strict";function bootProvidedReadOnly(){var providedRoot=document.getElementById("cdcfProvidedRoot");if(!providedRoot){return}var raw=providedRoot.getAttribute("data-cdcf");if(!raw){return}var data;try{data=JSON.parse(raw)}catch(e){return}Cdcf.init({container:providedRoot,initialData:data,lang:window._gpCdcfLang||{},projetNom:providedRoot.getAttribute("data-projet")||"",isLocked:true,onChange:function(){}})}function init(cfg){window._gpCdcfLang=cfg.lang;bootProvidedReadOnly();var dataField=document.getElementById("cdcfDataField");var root=document.getElementById("cdcfRoot");if(!root||!dataField){return}Cdcf.init({container:root,initialData:cfg.initial,lang:cfg.lang,projetNom:cfg.projetNom,isLocked:cfg.isLocked,onChange:function(data){dataField.value=JSON.stringify(data)}});$("#revertButton").on("click",function(){if(!window.confirm(cfg.confirmRevert)){return}Ajax.call([{methodname:"mod_gestionprojet_submit_step",args:{cmid:cfg.cmid,step:cfg.step,action:"revert"}}])[0].done(function(d){if(d.success){window.location.reload()}})});if(!cfg.isLocked){Autosave.init({cmid:cfg.cmid,step:cfg.step,groupid:cfg.groupid,interval:cfg.autosaveMs,formSelector:"#cdcfForm",serialize:function(){return{interacteurs_data:dataField.value}}})}}return{init:init}});